import requests

base_url = 'http://localhost:15672/api/'

def create_vhost(vhost_name):
    requests.put(base_url + 'vhosts/' + vhost_name, auth=('username', 'password'))

def create_user(username, password):
    requests.put(base_url + 'users/' + username, json={'password': password, 'tags': ''}, auth=('username', 'password'))

def set_permissions(vhost, username):
    requests.put(base_url + 'permissions/' + vhost + '/' + username, json={'configure': '.*', 'write': '.*', 'read': '.*'}, auth=('username', 'password'))

# Create vhosts for different applications
create_vhost('app1')
create_vhost('app2')

# Create users and set permissions
create_user('user1', 'password1')
set_permissions('app1', 'user1')

